def solve(points: Array[Array[Long]]): Long = {
    val n = points.length

    def gcd(a: Long, b: Long): Long = {
        var x = a
        var y = b
        while (y != 0) {
            val temp = x % y
            x = y
            y = temp
        }
        if (x < 0) -x else x
    }

    val slopeMap = mutable.Map.empty[(Long, Long), mutable.ArrayBuffer[(Int, Int)]]

    for {
        i <- 0 until n
        j <- i + 1 until n
    } {
        val x1 = points(i)(0)
        val y1 = points(i)(1)
        val x2 = points(j)(0)
        val y2 = points(j)(1)
        val dx = x2 - x1
        val dy = y2 - y1

        val key = 
            if (dx == 0 && dy == 0) (0L, 0L)
            else if (dx == 0) (0L, 1L)
            else if (dy == 0) (1L, 0L)
            else {
                var (ndx, ndy) = (dx, dy)
                if (dx < 0) {
                    ndx = -dx
                    ndy = -dy
                }
                val absDy = math.abs(ndy)
                val g = gcd(ndx, absDy)
                val sdx = ndx / g
                val sdy = if (ndy < 0) -(absDy / g) else absDy / g
                (sdx, sdy)
            }

        if (key != (0L, 0L)) {
            if (!slopeMap.contains(key)) {
                slopeMap(key) = mutable.ArrayBuffer.empty
            }
            slopeMap(key).append((i, j))
        }
    }

    var T = 0L
    for ((_, segments) <- slopeMap) {
        val m = segments.size
        val totalPairs = m * (m - 1L) / 2L
        val freq = mutable.Map[Int, Int]().withDefaultValue(0)
        for ((i, j) <- segments) {
            freq(i) += 1
            freq(j) += 1
        }
        var bad = 0L
        for ((_, cnt) <- freq) {
            bad += cnt.toLong * (cnt - 1).toLong / 2L
        }
        T += totalPairs - bad
    }

    val midMap = mutable.Map.empty[(Long, Long), Long]
    for {
        i <- 0 until n
        j <- i + 1 until n
    } {
        val mx = points(i)(0) + points(j)(0)
        val my = points(i)(1) + points(j)(1)
        midMap((mx, my)) = midMap.getOrElse((mx, my), 0L) + 1L
    }

    var P = 0L
    for ((_, cnt) <- midMap) {
        P += cnt * (cnt - 1) / 2
    }

    T - P
}
